// Entrada: { output: "Texto con \\n\\n saltos de línea" }
const output = $input.first().json.output;

// 1. Separa por uno o más saltos de línea
const paragraphs = output
  .split(/\n+/)          // divide donde haya \n, \n\n, etc.
  .map(s => s.trim())    // quita espacios al inicio/fin de cada párrafo
  .filter(Boolean);      // elimina entradas vacías

// 2. Devuelve un item por párrafo
return paragraphs.map(paragraph => ({
  json: { sentence: paragraph }
}));

// 1) Leemos la entrada completa
const entrada = $json;

// 2) Extraemos el array “messages”
const mensajes = Array.isArray(entrada.messages) ? entrada.messages : [];

// 3) Recorremos “mensajes” para detectar exactamente "__reloadFlag__" y filtramos
let encontradoFlag = false;
const filtered = mensajes.filter(item => {
  if (item.system === "__reloadFlag__") {
    encontradoFlag = true;
    return false; // excluimos este elemento
  }
  return true; // conservamos los demás
});

// 4) Devolvemos recargar=true si encontramos el flag y el array sin ese mensaje
return [
  {
    json: {
      recargar: encontradoFlag
    }
  }
];

/**
 * Este Function toma “entrada.messages.items” en orden cronológico (más antiguo → más reciente)
 * e intenta agrupar cada mensaje de usuario con su respuesta de IA/U operario contigua.
 * Además convierte broadcasts y plantillas en mensajes de IA, y mantiene el flag "__reloadFlag__" como mensaje de sistema.
 *
 * Salida:
 * [
 *   {
 *     "messages": [
 *       { "human": "texto usuario", "ai": "respuesta IA" },
 *       { "human": "otro usuario", "ai": "" },            // si no hubo respuesta contigua
 *       { "human": "", "ai": "texto broadcast" },          // broadcast sin human
 *       { "system": "__reloadFlag__" },                   // flag
 *       …
 *     ],
 *     "messagesCount": <número de elementos>
 *   }
 * ]
 */

const entrada = $input.all()[0].json;

// 1) Tomamos “items” y los invertimos a orden cronológico
const rawItems = Array.isArray(entrada.messages?.items) ? entrada.messages.items : [];
const rawEvents = rawItems.slice().reverse();

const messagesFormatted = [];
for (let i = 0; i < rawEvents.length; i++) {
  const ev = rawEvents[i];

  // 1.1) Flag de recarga
  if (ev.system === "__reloadFlag__") {
    messagesFormatted.push({ system: "__reloadFlag__" });
    continue;
  }

  // 1.2) Mensaje de usuario
  if (ev.eventType === "message" && ev.owner === false) {
    const humanText = ev.text || "";
    let aiText = "";

    // Si el siguiente evento existe y es un mensaje de IA operativo (owner=true, eventType="message"):
    if (i + 1 < rawEvents.length) {
      const next = rawEvents[i + 1];
      if (next.eventType === "message" && next.owner === true) {
        aiText = next.text || "";
        i++; // Skip the paired IA event
      }
    }

    messagesFormatted.push({ human: humanText, ai: aiText });
    continue;
  }

  // 1.3) BroadcastMessage (lo tratamos como IA)
  if (ev.eventType === "broadcastMessage") {
    const contenidoBroadcast = ev.finalText || "";
    messagesFormatted.push({ human: "", ai: contenidoBroadcast });
    continue;
  }

  // 1.4) Mensaje de IA/U operario no emparejado (owner=true, eventType="message")
  if (ev.eventType === "message" && ev.owner === true) {
    messagesFormatted.push({ human: "", ai: ev.text || "" });
    continue;
  }

  // 1.5) TemplateMessageSent_v2 (plantilla) → lo tratamos como IA
  if (ev.eventType === "templateMessageSent_v2") {
    messagesFormatted.push({ human: "", ai: ev.text || "" });
    continue;
  }

  // 1.6) Omitir cualquier otro evento de sistema (cierre de chat, inicialización, cambio de rol, etc.)
}

// 2) Construimos el resultado final
return [
  {
    json: {
      messages: messagesFormatted,
      messagesCount: messagesFormatted.length
    }
  }
];

/**
 * Toma un array de objetos { human: string, ai: string } y agrupa/consolida
 * de forma que:
 *  - Cuando haya un human seguido de un ai, se emparejen en un único objeto.
 *  - Si hay múltiples humans consecutivos antes de un ai, se concatenan en tempHuman.
 *  - Si hay múltiples ais consecutivos sin human, cada ai forma su propio objeto { human: "", ai }.
 *  - Al final, si queda un tempHuman sin ai, se añade { human: tempHuman, ai: "" }.
 */

const input = $input.all()[0].json.messages; // Array inicial

const resultado = [];
let tempHuman = "";
let tempAi = "";

// Iterar sobre cada elemento en orden
for (const item of input) {
  const h = item.human || "";
  const a = item.ai || "";

  if (h) {
    // Acumulamos texto de usuario
    tempHuman = tempHuman ? `${tempHuman} ${h}`.trim() : h;
  }

  if (a) {
    // Si hay un AI, lo emparejamos con cualquier tempHuman acumulado
    if (tempHuman) {
      resultado.push({ human: tempHuman.trim(), ai: a });
      tempHuman = "";
    } else {
      // Si no había human acumulado, este AI va solo
      resultado.push({ human: "", ai: a });
    }
    tempAi = ""; // Reset (no es necesario, pero por claridad)
  }
}

// Al terminar, si quedó texto de usuario sin AI asociado, lo añadimos
if (tempHuman) {
  resultado.push({ human: tempHuman.trim(), ai: "" });
}

return [
  {
    json: {
      messages: resultado,
      messagesCount: resultado.length
    }
  }
];

const madridTime = new Date().toLocaleString('en-US', {
  timeZone: 'Europe/Madrid',
});
const madridDate = new Date(madridTime);   // ahora sí lo parsea

const day  = madridDate.getDay();          // 0-domingo … 6-sábado
const hour = madridDate.getHours();

const isBH = day >= 1 && day <= 5 &&
             ((hour >= 10 && hour < 14) || (hour >= 17 && hour < 21));

return [{
  json: { isBH }
}];
